## Implementation

```rust
// src/cli/help.rs
use colored::*;
use crate::config::Config;

pub struct QuickstartOptions {
    pub color: bool,
    pub emoji: bool,
    pub show_status: bool,
}

impl Default for QuickstartOptions {
    fn default() -> Self {
        Self {
            color: atty::is(atty::Stream::Stdout),
            emoji: true,
            show_status: true,
        }
    }
}

pub fn print_quickstart(opts: QuickstartOptions) {
    let config = Config::load();

    // Header
    if opts.color {
        println!("{}", "╔══════════════════════════════════════════════════════════════╗".cyan());
        let emoji = if opts.emoji { "🎛️  " } else { "" };
        println!("{}  {}Surface Dial Volume Controller  {}{}",
            "║".cyan(),
            emoji,
            env!("CARGO_PKG_VERSION").bold(),
            "║".cyan());
        println!("{}", "╚══════════════════════════════════════════════════════════════╝".cyan());
    } else {
        println!("Surface Dial Volume Controller v{}\n", env!("CARGO_PKG_VERSION"));
    }
    println!();

    // Live status section
    if opts.show_status {
        print_status_section(&config, &opts);
    }

    // Controls section
    print_controls_section(&opts);

    // Features section
    print_features_section(&config, &opts);

    // Commands section
    print_commands_section(&opts);

    // Quick config examples
    print_config_examples(&opts);
}

fn print_status_section(config: &Config, opts: &QuickstartOptions) {
    println!("  {}:", "Status".bold());

    let daemon = check_daemon_status();
    let device = check_device_status();

    if daemon.running {
        let check = if opts.color { "✓".green().to_string() } else { "[OK]".to_string() };
        println!("    {} Daemon running (PID {}, uptime: {})", 
            check, daemon.pid.unwrap_or(0), format_uptime(daemon.uptime_seconds));
    } else {
        let x = if opts.color { "✗".red().to_string() } else { "[--]".to_string() };
        println!("    {} Daemon not running", x);
        println!("      Run: {} to start", "surface-dial daemon".cyan());
    }

    if device.connected {
        let check = if opts.color { "✓".green().to_string() } else { "[OK]".to_string() };
        let battery = device.battery.map(|b| format!(" (🔋 {}%)", b)).unwrap_or_default();
        println!("    {} Surface Dial connected{}", check, battery);
    } else {
        let x = if opts.color { "✗".red().to_string() } else { "[--]".to_string() };
        println!("    {} Surface Dial not connected", x);
        println!("      Wake the dial (press button) or check Bluetooth");
    }

    if daemon.running && device.connected {
        println!("    • Mode: {} at {}%", daemon.mode, daemon.volume);
    }

    println!();
    println!("  {}", "─────────────────────────────────────────────────────────────".dimmed());
    println!();
}

fn print_controls_section(opts: &QuickstartOptions) {
    println!("  {}:", "Controls".bold());
    println!("    {} Rotate             Adjust volume (speed-sensitive)", "↻".cyan());
    println!("    {} Click              Toggle mute", "⏺".cyan());
    println!("    {} Double-click      Switch to mic control (10s)", "⏺⏺".cyan());
    println!("    {} Triple-click     Play/Pause media", "⏺⏺⏺".cyan());
    println!("    {} Hold (1 sec)       Send F15 key (hold until release)", "⏸".cyan());
    println!("    {} Long-press + rotate  Cycle audio output devices", "⏸+↻".cyan());
    println!();
}

fn print_features_section(config: &Config, opts: &QuickstartOptions) {
    println!("  {}:", "Features".bold());

    let features = [
        (config.osd.enabled, "Visual OSD", "On-screen volume display"),
        (true, "Volume Curves", &format!("{} (matches human hearing)", config.volume.curve)),
        (config.battery.enabled, "Battery Monitor", "Low battery notifications"),
        (config.tray.enabled, "System Tray", "Menu bar icon with quick access"),
        (config.media_control.enabled, "Media Control", "Triple-click for Play/Pause"),
        (config.device_switching.enabled, "Device Switching", "Long-press + rotate"),
        (config.audio_feedback.enabled, "Audio Feedback", "Tick sounds"),
        (config.events.enabled, "Event Hooks", "Scripts and webhooks"),
    ];

    for (enabled, name, desc) in features {
        let icon = if enabled {
            if opts.color { "✓".green().to_string() } else { "[+]".to_string() }
        } else {
            if opts.color { "✗".dimmed().to_string() } else { "[-]".to_string() }
        };
        let status = if !enabled { "(disabled)".dimmed().to_string() } else { "".to_string() };
        println!("    {} {:16} {} {}", icon, name, desc.dimmed(), status);
    }

    println!();
    println!("  {}", "─────────────────────────────────────────────────────────────".dimmed());
    println!();
}

fn print_commands_section(opts: &QuickstartOptions) {
    println!("  {}:", "Commands".bold());
    println!("    {}                Show this quick-start guide", "surface-dial".cyan());
    println!("    {}         Start daemon in foreground", "surface-dial daemon".cyan());
    println!("    {}         Check daemon/device/battery status", "surface-dial status".cyan());
    println!("    {}         Show all configuration", "surface-dial config".cyan());
    println!("    {} Update setting K to value V", "surface-dial config set K V".cyan());
    println!("    {}  Watch logs in real-time", "surface-dial logs --follow".cyan());
    println!();

    // Config paths
    println!("  {}:", "Configuration".bold());
    let config_path = Config::path();
    let log_path = dirs::data_local_dir()
        .unwrap_or_default()
        .join("surface-dial")
        .join("daemon.log");
    println!("    📁 Config: {}", config_path.display().to_string().dimmed());
    println!("    📁 Logs:   {}", log_path.display().to_string().dimmed());
    println!();
}

fn print_config_examples(opts: &QuickstartOptions) {
    println!("  {}", "─────────────────────────────────────────────────────────────".dimmed());
    println!();
    println!("  {}:", "Quick Config Examples".bold());
    println!("    # Use linear volume curve");
    println!("    {}", "surface-dial config set volume.curve linear".cyan());
    println!();
    println!("    # Enable audio tick feedback");
    println!("    {}", "surface-dial config set audio_feedback.enabled true".cyan());
    println!();
    println!("    # Increase sensitivity");
    println!("    {}", "surface-dial config set sensitivity.multiplier 1.5".cyan());
    println!();
    println!("  For more: {} | {}", 
        "surface-dial --help".cyan(),
        "surface-dial config keys".cyan());
}

fn format_uptime(seconds: Option<u64>) -> String {
    match seconds {
        Some(s) => {
            let hours = s / 3600;
            let mins = (s % 3600) / 60;
            if hours > 0 {
                format!("{}h {}m", hours, mins)
            } else {
                format!("{}m", mins)
            }
        }
        None => "unknown".to_string()
    }
}
```

## Cross-Platform Considerations

- **Colors**: Use `colored` crate, auto-detects terminal support
- **Windows**: ANSI works in Windows Terminal, ConEmu, modern cmd.exe (Win10+)
- **Emoji**: Provide `--no-emoji` flag for terminals without emoji support
- **TTY detection**: Use `atty` crate to detect if stdout is a terminal

## CLI Integration

```rust
// In main.rs
fn main() {
    let cli = Cli::parse();

    match cli.command {
        None => {
            // No command = show quickstart
            help::print_quickstart(help::QuickstartOptions::default());
        }
        Some(cmd) => handle_command(cmd),
    }
}
```

## Dependencies

- `colored = "2"` - Cross-platform terminal colors
- `atty = "0.2"` - TTY detection

